def validate(args, output):
    import heapq
    n, edges, source, destination, target = args
    m = len(edges)

    adj = [[] for _ in range(n)]
    for i, (u, v, _w) in enumerate(edges):
        adj[u].append((v, i))
        adj[v].append((u, i))

    def dijkstra(weights):
        dist = [float('inf')] * n
        dist[source] = 0
        pq = [(0, source)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dist[u]:
                continue
            for v, i in adj[u]:
                nd = d + weights[i]
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(pq, (nd, v))
        return dist

    if output == []:
        w_min = [w if w != -1 else 1 for _, _, w in edges]
        w_max = [w if w != -1 else 2000000000 for _, _, w in edges]
        d_min = dijkstra(w_min)[destination]
        d_max = dijkstra(w_max)[destination]
        return d_min > target or d_max < target

    if not isinstance(output, list) or len(output) != m:
        return False

    remaining = {}
    for i, (u, v, w) in enumerate(edges):
        key = frozenset((u, v))
        remaining.setdefault(key, []).append((i, w))

    weights = [None] * m
    for item in output:
        if not (isinstance(item, list) and len(item) == 3):
            return False
        ou, ov, ow = item
        key = frozenset((ou, ov))
        bucket = remaining.get(key)
        if not bucket:
            return False
        idx, ew = bucket.pop()
        if not bucket:
            del remaining[key]
        if ew != -1:
            if ow != ew:
                return False
        else:
            if not isinstance(ow, int) or isinstance(ow, bool) or not (1 <= ow <= 2000000000):
                return False
        weights[idx] = ow

    if remaining or any(w is None for w in weights):
        return False

    dist = dijkstra(weights)
    return dist[destination] == target

