function validate(args, output) {
    const [n, edges, source, destination, target] = args;
    const m = edges.length;
    const adj = Array.from({ length: n }, () => []);
    edges.forEach(([u, v], i) => { adj[u].push([v, i]); adj[v].push([u, i]); });

    function dijkstra(weights) {
        const dist = new Array(n).fill(Infinity);
        dist[source] = 0;
        const pq = [[0, source]];
        while (pq.length) {
            let mi = 0;
            for (let i = 1; i < pq.length; i++) if (pq[i][0] < pq[mi][0]) mi = i;
            const [d, u] = pq.splice(mi, 1)[0];
            if (d > dist[u]) continue;
            for (const [v, i] of adj[u]) {
                const nd = d + weights[i];
                if (nd < dist[v]) { dist[v] = nd; pq.push([nd, v]); }
            }
        }
        return dist;
    }

    if (Array.isArray(output) && output.length === 0) {
        const wMin = edges.map(([, , w]) => (w === -1 ? 1 : w));
        const wMax = edges.map(([, , w]) => (w === -1 ? 2000000000 : w));
        const dMin = dijkstra(wMin)[destination];
        const dMax = dijkstra(wMax)[destination];
        return dMin > target || dMax < target;
    }

    if (!Array.isArray(output) || output.length !== m) return false;

    const remaining = new Map();
    edges.forEach(([u, v, w], i) => {
        const key = [Math.min(u, v), Math.max(u, v)].join(',');
        if (!remaining.has(key)) remaining.set(key, []);
        remaining.get(key).push([i, w]);
    });

    const weights = new Array(m).fill(null);
    for (const item of output) {
        if (!Array.isArray(item) || item.length !== 3) return false;
        const [ou, ov, ow] = item;
        const key = [Math.min(ou, ov), Math.max(ou, ov)].join(',');
        const bucket = remaining.get(key);
        if (!bucket || bucket.length === 0) return false;
        const [idx, ew] = bucket.pop();
        if (bucket.length === 0) remaining.delete(key);
        if (ew !== -1) {
            if (ow !== ew) return false;
        } else {
            if (!Number.isInteger(ow) || ow < 1 || ow > 2000000000) return false;
        }
        weights[idx] = ow;
    }

    if (remaining.size > 0 || weights.some((w) => w === null)) return false;

    const dist = dijkstra(weights);
    return dist[destination] === target;
}

