import heapq
from collections import defaultdict

class Solution:
    def modifiedGraphEdges(self, n, edges, source, destination, target):
        adj = defaultdict(list)
        for i, (u, v, w) in enumerate(edges):
            adj[u].append((v, i))
            adj[v].append((u, i))

        def dijkstra(weights):
            dist = [float('inf')] * n
            dist[source] = 0
            pq = [(0, source)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, i in adj[u]:
                    nd = d + weights[i]
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist

        weights = [w if w != -1 else 1 for _, _, w in edges]
        dist = dijkstra(weights)
        if dist[destination] > target:
            return []
        if dist[destination] == target:
            return [[u, v, weights[i]] for i, (u, v, w) in enumerate(edges)]

        for i, (u, v, w) in enumerate(edges):
            if w != -1:
                continue
            cur_dist = dijkstra(weights)[destination]
            if cur_dist < target:
                weights[i] = 1 + (target - cur_dist)
                if dijkstra(weights)[destination] == target:
                    break

        final_dist = dijkstra(weights)[destination]
        if final_dist == target:
            return [[u, v, weights[i]] for i, (u, v, w) in enumerate(edges)]
        return []

