    const m = edges.length;
    const adj = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const [u, v] = edges[i];
        adj[u].push([v, i]);
        adj[v].push([u, i]);
    }

    function dijkstra(weights) {
        const dist = new Array(n).fill(Infinity);
        dist[source] = 0;
        const pq = [[0, source]];
        while (pq.length) {
            let mi = 0;
            for (let i = 1; i < pq.length; i++) if (pq[i][0] < pq[mi][0]) mi = i;
            const [d, u] = pq.splice(mi, 1)[0];
            if (d > dist[u]) continue;
            for (const [v, i] of adj[u]) {
                const nd = d + weights[i];
                if (nd < dist[v]) { dist[v] = nd; pq.push([nd, v]); }
            }
        }
        return dist;
    }

    const weights = edges.map(([, , w]) => (w === -1 ? 1 : w));
    let dist = dijkstra(weights);
    if (dist[destination] > target) return [];
    if (dist[destination] === target) {
        return edges.map((e, i) => [e[0], e[1], weights[i]]);
    }

    for (let i = 0; i < m; i++) {
        if (edges[i][2] !== -1) continue;
        const curDist = dijkstra(weights)[destination];
        if (curDist < target) {
            weights[i] = 1 + (target - curDist);
            if (dijkstra(weights)[destination] === target) break;
        }
    }

    const finalDist = dijkstra(weights)[destination];
    if (finalDist === target) {
        return edges.map((e, i) => [e[0], e[1], weights[i]]);
    }
    return [];
};
